#include <vector>
#include <algorithm>

int partition(std::vector<int>& arr, int low, int high);
void quicksort(std::vector<int>& arr, int low, int high);

void adaptive_sort(std::vector<int>& arr) {
    if (arr.size() < 2) return;
    bool sorted = true;
    for (int i = 1; i < (int)arr.size(); ++i)
        if (arr[i] < arr[i-1]) { sorted = false; break; }
    if (!sorted) quicksort(arr, 0, (int)arr.size() - 1);
}

void quicksort(std::vector<int>& arr, int low, int high) {
    while (low < high) {
        if (high - low < 16) {
            for (int i = low + 1; i <= high; ++i) {
                int k = arr[i], j = i - 1;
                while (j >= low && arr[j] > k) { arr[j+1] = arr[j]; j--; }
                arr[j+1] = k;
            }
            return;
        }
        int p = partition(arr, low, high);
        if (p - low < high - p) { quicksort(arr, low, p - 1); low = p + 1; }
        else { quicksort(arr, p + 1, high); high = p - 1; }
    }
}

int partition(std::vector<int>& arr, int low, int high) {
    int m = low + (high - low) / 2;
    if (arr[m] < arr[low]) std::swap(arr[m], arr[low]);
    if (arr[high] < arr[low]) std::swap(arr[high], arr[low]);
    if (arr[high] < arr[m]) std::swap(arr[high], arr[m]);
    std::swap(arr[m], arr[high]);
    int pivot = arr[high], i = low;
    for (int j = low; j < high; ++j)
        if (arr[j] < pivot) std::swap(arr[i++], arr[j]);
    std::swap(arr[i], arr[high]);
    return i;
}

